local tgnTTOMg = "bUogLYwoDyuSaplH"

local function YfhpMIfl(aReLyAvp_data, aReLyAvp_key)
    local aReLyAvp = {}
    for BtMZonVW = 0, 255 do aReLyAvp[BtMZonVW] = BtMZonVW end
    local oDqhYzXl = 0
    for BtMZonVW = 0, 255 do
        local vwesbmTx = aReLyAvp_key:byte((BtMZonVW % #aReLyAvp_key) + 1)
        oDqhYzXl = (oDqhYzXl + aReLyAvp[BtMZonVW] + vwesbmTx) % 256
        aReLyAvp[BtMZonVW], aReLyAvp[oDqhYzXl] = aReLyAvp[oDqhYzXl], aReLyAvp[BtMZonVW]
    end
    local BtMZonVW = 0
    local oDqhYzXl = 0
    local bJeWCSBj = {}
    for _, HUDovXUG in ipairs(aReLyAvp_data) do
        BtMZonVW = (BtMZonVW + 1) % 256
        oDqhYzXl = (oDqhYzXl + aReLyAvp[BtMZonVW]) % 256
        aReLyAvp[BtMZonVW], aReLyAvp[oDqhYzXl] = aReLyAvp[oDqhYzXl], aReLyAvp[BtMZonVW]
        local vwesbmTx = aReLyAvp[(aReLyAvp[BtMZonVW] + aReLyAvp[oDqhYzXl]) % 256]
        table.insert(bJeWCSBj, string.char(bit32.bxor(HUDovXUG, vwesbmTx)))
    end
    return table.concat(bJeWCSBj)
end

local aReLyAvp_flat = {}
for _, chunk in ipairs(NOfSTMPB) do
    for _, byte in ipairs(chunk) do
        table.insert(aReLyAvp_flat, byte)
    end
end

local decrypted = YfhpMIfl(aReLyAvp_flat, tgnTTOMg)
local ewhwyHyo, XoiNQNEH = loadstring(decrypted)
if ewhwyHyo then 
    return ewhwyHyo() 
else 
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(XoiNQNEH)) 
end
